import{d as a}from"./index-CjyuK5MW.js";class c{async getGlobalStats(){return(await a.get("/super-admin/stats")).data}async getAllCompanies(s){return(await a.get("/super-admin/companies",{params:s})).data}async getCompanyById(s){return(await a.get(`/super-admin/companies/${s}`)).data}async getContaUsers(){return(await a.get("/super-admin/conta-users")).data}async createContaUser(s){return(await a.post("/super-admin/conta-users",s)).data}async updateContaUser(s,e){return(await a.put(`/super-admin/conta-users/${s}`,e)).data}async deleteContaUser(s){return(await a.delete(`/super-admin/conta-users/${s}`)).data}async getPackages(){var r,o;const s=await a.get("/super-admin/packages"),e=(r=s.data)==null?void 0:r.data,n=(Array.isArray(e)?e:[]).map(p=>({...p,price:p.price||0}));return{success:((o=s.data)==null?void 0:o.success)??!0,data:n}}async getAccountants(s){return(await a.get("/accountants/search",{params:s})).data}async createPackage(s){return(await a.post("/packages",s)).data}async updatePackage(s,e){return(await a.put(`/packages/${s}`,e)).data}async deletePackage(s,e=!1){return(await a.delete(`/packages/${s}`,{params:{force:e}})).data}async getPackageSubscriptionsCount(s){return(await a.get(`/packages/${s}/subscriptions-count`)).data}async getPackageModificationImpact(s,e,t){return(await a.post(`/super-admin/packages/${s}/impact`,{limits:e,features:t})).data}async getPackageHistory(s){return(await a.get(`/super-admin/packages/${s}/history`)).data}async getUserPermissions(s){return(await a.get(`/super-admin/conta-users/${s}/permissions`)).data}async updateUserPermissions(s,e){return(await a.put(`/super-admin/conta-users/${s}/permissions`,e)).data}async resetUserPermissions(s){return(await a.post(`/super-admin/conta-users/${s}/permissions/reset`)).data}async getSubscriptionsWithPayments(s){return(await a.get("/super-admin/subscriptions/payments",{params:s})).data}async getPaymentStatistics(){return(await a.get("/super-admin/subscriptions/payments/statistics")).data}async recordSubscriptionPayment(s,e){return(await a.post(`/super-admin/subscriptions/${s}/payments`,e)).data}async getSubscriptionPaymentHistory(s){return(await a.get(`/super-admin/subscriptions/${s}/payments/history`)).data}async approveAccountant(s){return(await a.post(`/super-admin/accountants/${s}/approve`)).data}async rejectAccountant(s,e){return(await a.post(`/super-admin/accountants/${s}/reject`,{reason:e})).data}async getMonthlyRevenueData(){return(await a.get("/super-admin/stats/monthly-revenue")).data}async getCompanyGrowthData(){return(await a.get("/super-admin/stats/company-growth")).data}}const d=new c;export{d as a};
